parameters.inputSchema:
{
    "type": "object",
    "properties": {
        "search_summary": {
            "type": "string",
            "description": "Detailed summary of the search query and results overview"
        },
        "total_listings_found": {
            "type": "integer",
            "description": "Total number of listings returned"
        },
        "search_location": {
            "type": "string",
            "description": "Primary search location/destination"
        },
        "guest_count": {
            "type": "integer",
            "description": "Number of guests the search was for"
        },
        "price_range": {
            "type": "string",
            "description": "Price range of all listings (e.g., '$489 - $879 USD for 5 nights')"
        },
        "listings": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "property_name": {
                        "type": "string",
                        "description": "Property/listing name or title"
                    },
                    "property_link": {
                        "type": "string",
                        "description": "Direct Airbnb listing URL"
                    },
                    "location_details": {
                        "type": "string",
                        "description": "Specific location (neighborhood, area, city)"
                    },
                    "property_type": {
                        "type": "string",
                        "description": "Type of accommodation (villa, private room, entire home, etc.)"
                    },
                    "standout_features": {
                        "type": "string",
                        "description": "Key features that make this property special (pool, beach access, views, etc.)"
                    },
                    "why_recommended": {
                        "type": "string",
                        "description": "Detailed reasons why this property matches the user's search criteria."
                    },
                    "value_assessment": {
                        "type": "string",
                        "enum": ["Excellent Value", "Good Value", "Premium Pricing", "Budget Option"],
                        "description": "Value for money assessment"
                    },
                    "guest_rating": {
                        "type": "number",
                        "description": "Average guest rating out of 5.0"
                    },
                    "review_count": {
                        "type": "integer",
                        "description": "Total number of reviews"
                    },
                    "total_price": {
                        "type": "string",
                        "description": "Total price for the entire stay in USD"
                    },
                    "cancellation_policy": {
                        "type": "string",
                        "description": "Cancellation policy details"
                    },
                    "booking_urgency": {
                        "type": "string",
                        "enum": ["High", "Medium", "Low"],
                        "description": "Recommended booking urgency based on availability and demand"
                    },
                    "booking_timing_advice": {
                        "type": "string",
                        "description": "Advice on when to book based on how far the check-in date is from today. Examples: 'Prices may still drop — monitor before booking' (>60 days), 'Good time to book — prices are typically stable now' (14-60 days), 'Book immediately — last-minute prices are usually highest' (<14 days)"
                    },
                    "target_traveler": {
                        "type": "string",
                        "description": "Who this property is best suited for (couples, families, solo travelers, etc.)"
                    }
                },
                "required": [
                    "property_name",
                    "property_link",
                    "location_details",
                    "property_type",
                    "standout_features",
                    "why_recommended",
                    "value_assessment",
                    "guest_rating",
                    "review_count",
                    "total_price",
                    "cancellation_policy",
                    "booking_urgency",
                    "booking_timing_advice",
                    "target_traveler"
                ]
            }
        },
        "recommendation_summary": {
            "type": "string",
            "description": "Overall recommendation and next steps for the traveler"
        },
        "additional_search_link": {
            "type": "string",
            "description": "Link to browse more options on Airbnb"
        }
    },
    "required": [
        "search_summary",
        "total_listings_found",
        "search_location",
        "guest_count",
        "price_range",
        "listings",
        "recommendation_summary"
    ]
}

parameters.text:
=Rewrite the following into the structured output format exactly as specified. Include all required fields and examples: {{ $json.output }}

Be as detailed as possible but do not fabricate information. If a field is unknown or missing, set it to "Unknown" and note which data is unavailable.

If there are no listings, reply exactly: "Unfortunately we couldn't find listings that match your request."
